{{ombox
| type = notice
| imageright = [[File:Trash Can (wish cross).svg|40px|link=|alt=]]
| text = An editor has marked this as a <em>promising draft</em> {{#if: {{{reason|}}} | because ''' {{{reason|}}}''',}} and requests that, should it go unedited for six months, [[WP:G13|G13]] deletion be postponed, either by making a [[Help:Dummy edit|dummy]]/[[Help:Minor edit|minor]] edit to the page, or by improving and submitting it for review.<br />{{last edited by|brief=yes}}
}}
{{Category handler
|draft=[[Category:Promising draft articles]]
|user=[[Category:Promising draft articles]]<noinclude><!-- userspace drafts sometimes get marked with this template --></noinclude>
|other=<includeonly>[[Category:Misused Promising draft template]]</includeonly>
|demospace={{{demospace|}}}
}}<noinclude>
{{documentation}}
</noinclude>

